package com.kanati.admin.components

import androidx.compose.runtime.Composable
import com.kanati.admin.state.MaterialThemePalette
import org.jetbrains.compose.web.css.DisplayStyle
import org.jetbrains.compose.web.css.borderRadius
import org.jetbrains.compose.web.css.display
import org.jetbrains.compose.web.css.flexDirection
import org.jetbrains.compose.web.css.gap
import org.jetbrains.compose.web.css.margin
import org.jetbrains.compose.web.css.padding
import org.jetbrains.compose.web.css.px
import org.jetbrains.compose.web.dom.Div
import org.jetbrains.compose.web.dom.H2
import org.jetbrains.compose.web.dom.P
import org.jetbrains.compose.web.dom.Text

@Composable
fun SectionCard(
    title: String,
    theme: MaterialThemePalette,
    description: String? = null,
    headerActions: (@Composable () -> Unit)? = null,
    content: @Composable () -> Unit,
) {
    Div(
        attrs = {
            style {
                borderRadius(30.px)
                padding(24.px)
                display(DisplayStyle.Flex)
                flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                gap(16.px)
                property(
                    "background",
                    "linear-gradient(180deg, ${theme.surfaceContainerHighest} 0%, ${theme.surface} 100%)"
                )
                property("border", "1px solid ${theme.outlineVariant}")
                property("box-shadow", "0 22px 56px ${theme.shadow}, inset 0 1px 0 ${theme.scrim}")
                property("backdrop-filter", "blur(26px) saturate(170%)")
                property("position", "relative")
                property("overflow", "hidden")
            }
        }
    ) {
        Div(
            attrs = {
                style {
                    property("position", "absolute")
                    property("top", "0")
                    property("left", "0")
                    property("right", "0")
                    property("height", "120px")
                    property(
                        "background",
                        "linear-gradient(180deg, ${theme.scrim} 0%, ${theme.surfaceTint} 32%, transparent 100%)"
                    )
                    property("pointer-events", "none")
                }
            }
        )

        Div(
            attrs = {
                style {
                    property("position", "relative")
                    property("z-index", "1")
                    display(DisplayStyle.Flex)
                    flexDirection(org.jetbrains.compose.web.css.FlexDirection.Column)
                    gap(16.px)
                }
            }
        ) {
            Div(
                attrs = {
                    style {
                        property("display", "flex")
                        property("justify-content", "space-between")
                        property("align-items", "start")
                        property("gap", "14px")
                        property("flex-wrap", "wrap")
                    }
                }
            ) {
                Div(
                    attrs = {
                        style {
                            property("display", "flex")
                            property("flex-direction", "column")
                            property("gap", "10px")
                            property("max-width", "720px")
                        }
                    }
                ) {
                    H2(
                        attrs = {
                            style {
                                margin(0.px)
                                property("color", theme.onSurface)
                                property("font-family", "\"SF Pro Display\", \"Avenir Next\", sans-serif")
                                property("font-size", "1.6rem")
                                property("line-height", "1.02")
                                property("letter-spacing", "-0.04em")
                            }
                        }
                    ) {
                        Text(title)
                    }

                    description?.let {
                        P(
                            attrs = {
                                style {
                                    margin(0.px)
                                    property("color", theme.onSurfaceVariant)
                                    property("font-size", "0.96rem")
                                    property("line-height", "1.55")
                                }
                            }
                        ) {
                            Text(it)
                        }
                    }
                }

                headerActions?.let { actions ->
                    Div(
                        attrs = {
                            style {
                                property("display", "flex")
                                property("align-items", "center")
                                property("gap", "10px")
                                property("flex-wrap", "wrap")
                            }
                        }
                    ) {
                        actions()
                    }
                }
            }

            content()
        }
    }
}
