private enum class EventFilter(val label: String) {
    Active("Upcoming/Active"),
    Archived("Archived"),
    All("All"),
}

private data class ManageEventDialogState(
    val event: EventDto,
)

private data class TicketEntitlementDraft(
    val type: TicketEntitlementType = TicketEntitlementType.CONCESSION_CREDIT,
    val label: String = "",
    val amountInput: String = "",
    val quantityInput: String = "",
)

private data class TicketTierDraft(
    val id: String? = null,
    val name: String = "",
    val priceInput: String = "",
    val capacityInput: String = "",
    val active: Boolean = true,
    val entitlements: List<TicketEntitlementDraft> = emptyList(),
)

private data class CapacityDialogState(
    val currentCapacity: Int?,
    val initialDraft: String,
)

private enum class TimeMeridiem {
    AM,
    PM,
}

private data class TimePickerDraft(
    val hour: Int? = null,
    val minute: Int? = null,
    val meridiem: TimeMeridiem = TimeMeridiem.AM,
)

private data class WheelOption<T>(
    val value: T,
    val label: String,
)

private const val TimeWheelRowHeightPx = 52
private const val TimeWheelVisibleRows = 5
private const val TimeWheelSidePaddingRows = 2

@Composable
fun EventsScreen(
    apiClient: AdminApiClient,
    district: SelectedDistrictContext?,
    school: SelectedSchoolContext?,
    districtLoading: Boolean,
    districtLoadError: String?,
    theme: MaterialThemePalette,
    canEdit: Boolean,
) {
    val scope = rememberCoroutineScope()
    val localTimeZoneLabel = remember { browserTimeZoneLabel() }
    var events by remember { mutableStateOf<List<EventDto>>(emptyList()) }
    var isRefreshing by remember { mutableStateOf(false) }
    var isSubmitting by remember { mutableStateOf(false) }
    var loadError by remember { mutableStateOf<String?>(null) }

    var createError by remember { mutableStateOf<String?>(null) }
    var createSuccess by remember { mutableStateOf<String?>(null) }
    var draftName by remember { mutableStateOf("") }
    var draftLocation by remember { mutableStateOf("") }
    var draftStartDate by remember { mutableStateOf("") }
    var draftStartTime by remember { mutableStateOf(TimePickerDraft()) }
    var draftEndDate by remember { mutableStateOf("") }
    var draftEndTime by remember { mutableStateOf(TimePickerDraft()) }
    var draftCapacity by remember { mutableStateOf<Int?>(null) }
    var draftTicketTiers by remember { mutableStateOf(listOf(defaultTicketTierDraft())) }

    var validationCode by remember { mutableStateOf("") }
    var validationError by remember { mutableStateOf<String?>(null) }
    var validationSuccess by remember { mutableStateOf<String?>(null) }
    var isValidating by remember { mutableStateOf(false) }

    var manageDialog by remember { mutableStateOf<ManageEventDialogState?>(null) }
    var eventFilter by remember { mutableStateOf(EventFilter.Active) }

    fun sortedEvents(items: List<EventDto>): List<EventDto> =
        items.sortedBy { it.startDate }

    fun mergeEvent(updated: EventDto) {
        var replaced = false
        events = sortedEvents(
            events.map { existing ->
                if (existing.id == updated.id) {
                    replaced = true
                    updated
                } else {
                    existing
                }
            }.let { current -> if (replaced) current else current + updated }
        )
    }

    suspend fun refreshEvents(
        selectedDistrict: SelectedDistrictContext,
        selectedSchool: SelectedSchoolContext,
    ) {
        isRefreshing = true
        loadError = null
        try {
            events = sortedEvents(apiClient.getEvents(selectedDistrict.id, selectedSchool.id))
        } catch (exception: Exception) {
            loadError = exception.message ?: "Unable to load events."
        } finally {
            isRefreshing = false
        }
    }

    LaunchedEffect(district?.id, school?.id) {
        if (district != null && school != null) {
            refreshEvents(district, school)
        } else {
            events = emptyList()
        }
    }

    fun submitValidation() {
        val selectedDistrict = district ?: return
        val selectedSchool = school ?: return
        if (validationCode.isBlank() || isValidating) return

        scope.launch {
            isValidating = true
            validationError = null
            validationSuccess = null
            try {
                val response = apiClient.checkInTicket(
                    districtId = selectedDistrict.id,
                    schoolId = selectedSchool.id,
                    request = TicketCheckInRequest(ticketCode = validationCode.trim()),
                )
                if (response.success) {
                    validationSuccess = "Entry validated for ${response.ticket?.ticketTierName ?: "ticket"} (${response.ticket?.ticketCode})"
                    validationCode = ""
                } else {
                    validationError = response.message
                }
            } catch (exception: Exception) {
                validationError = exception.message ?: "Unable to validate ticket."
            } finally {
                isValidating = false
            }
        }
    }

    fun submitCreateEvent() {
        val selectedDistrict = district ?: return
        val selectedSchool = school ?: return
        val ticketTierRequests = draftTicketTiers.toCreateRequests() ?: return
        val startTimeValue = draftStartTime.toLocalTimeValueOrNull()
        val endTimeValue = draftEndTime.toLocalTimeValueOrNull()
        val startDateIso = startTimeValue?.let { parseLocalDateAndTimeInputToIso(draftStartDate, it) }
        val endDateIso = endTimeValue?.let { parseLocalDateAndTimeInputToIso(draftEndDate, it) }
        if (
            draftName.isBlank() ||
            draftLocation.isBlank() ||
            draftStartDate.isBlank() ||
            !draftStartTime.isComplete() ||
            draftEndDate.isBlank() ||
            !draftEndTime.isComplete() ||
            startDateIso == null ||
            endDateIso == null
        ) return

        scope.launch {
            createError = null
            createSuccess = null
            isSubmitting = true
            try {
                val created = apiClient.createEvent(
                    CreateEventRequest(
                        districtId = selectedDistrict.id,
                        schoolId = selectedSchool.id,
                        name = draftName,
                        startDate = startDateIso,
                        endDate = endDateIso,
                        location = draftLocation,
                        capacity = draftCapacity,
                        ticketTiers = ticketTierRequests,
                    )
                )
                mergeEvent(created)
                createSuccess = "Event '${created.name}' created."
                draftName = ""
                draftLocation = ""
                draftStartDate = ""
                draftStartTime = TimePickerDraft()
                draftEndDate = ""
                draftEndTime = TimePickerDraft()
                draftCapacity = null
                draftTicketTiers = listOf(defaultTicketTierDraft())
            } catch (exception: Exception) {
                createError = exception.message ?: "Unable to create event."
            } finally {
                isSubmitting = false
            }
        }
    }

    val visibleEvents = events.filter { event ->
        when (eventFilter) {
            EventFilter.Active -> event.active
            EventFilter.Archived -> !event.active
            EventFilter.All -> true
        }
    }
    val createMissingRequirements = remember(
        draftName,
        draftLocation,
        draftStartDate,
        draftStartTime,
        draftEndDate,
        draftEndTime,
        draftTicketTiers,
    ) {
        buildCreateEventMissingRequirements(
            eventName = draftName,
            location = draftLocation,
            startDate = draftStartDate,
            startTime = draftStartTime,
            endDate = draftEndDate,
            endTime = draftEndTime,
            ticketTiers = draftTicketTiers,
        )
    }
    val createButtonDisabled = isSubmitting || createMissingRequirements.isNotEmpty()

    if (district == null || districtLoading || districtLoadError != null) {
        Div({ style { padding(24.px) } }) {
            P({ style { property("color", theme.onSurfaceVariant) } }) {
                Text(
                    when {
                        districtLoading -> "Loading district context..."
                        districtLoadError != null -> "District context could not be loaded."
                        else -> "Select a district to manage events."
                    }
                )
            }
        }
        return
    }

    Div({
        style {
            padding(24.px)
            display(DisplayStyle.Flex)
            flexDirection(FlexDirection.Column)
            gap(24.px)
        }
    }) {
        SectionCard(
            title = "Events",
            description = "Configure district-scoped events with multiple ticket tiers and simple entitlement bundles. Ticket validation remains server-authoritative, but admin is no longer treated as the long-term scanning surface.",
            theme = theme,
            headerActions = {
                EventFilter.entries.forEach { filter ->
                    ChoiceChip(
                        label = filter.label,
                        isSelected = eventFilter == filter,
                        onClick = { eventFilter = filter },
                        theme = theme,
                    )
                }
            },
        ) {
            Div({
                style {
                    display(DisplayStyle.Flex)
                    flexDirection(FlexDirection.Column)
                    gap(12.px)
                }
            }) {
                loadError?.let { StatusBanner(it, tone = BannerTone.Error, theme = theme) }
                if (visibleEvents.isEmpty() && !isRefreshing) {
                    P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                        Text("No events found for the selected filter.")
                    }
                } else {
                    visibleEvents.forEach { event ->
                        Div({
                            style {
                                padding(18.px)
                                borderRadius(24.px)
                                property("border", "1px solid ${theme.outlineVariant}")
                                property("background-color", if (event.active) theme.surface else theme.surfaceVariant)
                                display(DisplayStyle.Flex)
                                property("justify-content", "space-between")
                                property("align-items", "flex-start")
                                property("gap", "16px")
                                property("flex-wrap", "wrap")
                            }
                        }) {
                            Div({
                                style {
                                    display(DisplayStyle.Flex)
                                    flexDirection(FlexDirection.Column)
                                    gap(8.px)
                                    property("max-width", "720px")
                                }
                            }) {
                                H3({ style { margin(0.px); property("color", theme.onSurface) } }) {
                                    Text(event.name)
                                    if (!event.active) {
                                        Text(" (Archived)")
                                    }
                                }
                                P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                                    Text("${formatLocalDateTimeDisplay(event.startDate)} · ${event.location} · ${formatStartingPrice(event)} · ${formatCapacitySummary(event.capacity)}")
                                }
                                Div({
                                    style {
                                        display(DisplayStyle.Flex)
                                        gap(8.px)
                                        property("flex-wrap", "wrap")
                                    }
                                }) {
                                    event.ticketTiers.forEach { ticketTier ->
                                        ChoiceChip(
                                            label = tierSummary(ticketTier),
                                            isSelected = ticketTier.active,
                                            onClick = {},
                                            theme = theme,
                                            isInteractive = false,
                                        )
                                    }
                                }
                            }
                            ActionButton(
                                label = "Manage",
                                onClick = { manageDialog = ManageEventDialogState(event) },
                                theme = theme,
                                isPrimary = false,
                            )
                        }
                    }
                }
            }
        }

        SectionCard(
            title = "Create Event",
            description = "Start with the real selling surface in mind: define the event once, then add the ticket tiers and entitlement bundles that future POS and gate clients will rely on.",
            theme = theme,
        ) {
            Div({
                style {
                    display(DisplayStyle.Flex)
                    flexDirection(FlexDirection.Column)
                    gap(16.px)
                }
            }) {
                createError?.let { StatusBanner(it, tone = BannerTone.Error, theme = theme) }
                createSuccess?.let { StatusBanner(it, tone = BannerTone.Success, theme = theme) }

                FieldRow {
                    TextField(
                        theme = theme,
                        label = "Event Name",
                        value = draftName,
                        onValueChange = { draftName = it },
                        placeholder = "Friday Night Football",
                    )
                    TextField(
                        theme = theme,
                        label = "Location",
                        value = draftLocation,
                        onValueChange = { draftLocation = it },
                        placeholder = "Main Stadium",
                    )
                }
                FieldRow {
                    LargePickerField(
                        theme = theme,
                        label = "Start Date",
                        value = draftStartDate,
                        onValueChange = { draftStartDate = it },
                        inputTypeOverride = "date",
                    )
                    AlarmTimePickerField(
                        theme = theme,
                        label = "Start Time",
                        value = draftStartTime,
                        onValueChange = { draftStartTime = it },
                    )
                }
                FieldRow {
                    LargePickerField(
                        theme = theme,
                        label = "End Date",
                        value = draftEndDate,
                        onValueChange = { draftEndDate = it },
                        inputTypeOverride = "date",
                    )
                    AlarmTimePickerField(
                        theme = theme,
                        label = "End Time",
                        value = draftEndTime,
                        onValueChange = { draftEndTime = it },
                    )
                }
                P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                    Text("Dates and times use your current local time zone: $localTimeZoneLabel. Tap the time field to open the picker wheel.")
                }
                CapacityField(
                    theme = theme,
                    label = "Event Capacity",
                    capacity = draftCapacity,
                    supportingText = "Use + / - for small changes. Tap the value to set an exact cap or explicitly switch back to Unlimited.",
                    dialogTitle = "Set Event Capacity",
                    dialogSubjectLabel = "event",
                    onCapacityChange = { draftCapacity = it },
                )

                TicketTierEditor(
                    title = "Ticket Tiers",
                    drafts = draftTicketTiers,
                    theme = theme,
                    onDraftsChange = { draftTicketTiers = it },
                )

                CreateEventRequirementsPanel(
                    theme = theme,
                    missingRequirements = createMissingRequirements,
                )

                ActionButton(
                    label = if (isSubmitting) "Creating..." else "Create Event",
                    onClick = { submitCreateEvent() },
                    isDisabled = createButtonDisabled,
                    theme = theme,
                )
            }
        }

        SectionCard(
            title = "Transitional Gate Validation",
            description = "This stays available for MVP verification, but the long-term scanning home is a dedicated gate or POS client. The server contract and route shape already point in that direction.",
            theme = theme,
        ) {
            Div({
                style {
                    display(DisplayStyle.Flex)
                    flexDirection(FlexDirection.Column)
                    gap(16.px)
                }
            }) {
                validationError?.let { StatusBanner(it, tone = BannerTone.Error, theme = theme) }
                validationSuccess?.let { StatusBanner(it, tone = BannerTone.Success, theme = theme) }
                FieldRow {
                    TextField(
                        theme = theme,
                        label = "Ticket Code",
                        value = validationCode,
                        onValueChange = { validationCode = it },
                        placeholder = "Scan or paste a ticket code",
                    )
                }
                Div({
                    style {
                        display(DisplayStyle.Flex)
                        gap(8.px)
                        property("flex-wrap", "wrap")
                    }
                }) {
                    ActionButton(
                        label = if (isValidating) "Validating..." else "Validate Entry",
                        onClick = { submitValidation() },
                        isDisabled = isValidating || validationCode.isBlank(),
                        theme = theme,
                    )
                    ActionButton(
                        label = "Clear",
                        onClick = {
                            validationCode = ""
                            validationError = null
                            validationSuccess = null
                        },
                        theme = theme,
                        isPrimary = false,
                        isDisabled = isValidating,
                    )
                }
            }
        }
    }

    manageDialog?.let { dialog ->
        ManageEventDialog(
            apiClient = apiClient,
            districtId = district.id,
            event = dialog.event,
            theme = theme,
            onClose = { manageDialog = null },
            onUpdate = { updated ->
                mergeEvent(updated)
                manageDialog = ManageEventDialogState(updated)
            },
        )
    }
}

@Composable
private fun ManageEventDialog(
    apiClient: AdminApiClient,
    districtId: String,
    event: EventDto,
    theme: MaterialThemePalette,
    onClose: () -> Unit,
    onUpdate: (EventDto) -> Unit,
) {
    val scope = rememberCoroutineScope()
    val localTimeZoneLabel = remember { browserTimeZoneLabel() }
    var currentEvent by remember { mutableStateOf(event) }
    var stats by remember { mutableStateOf<EventStatsDto?>(null) }
    var isLoadingStats by remember { mutableStateOf(true) }

    var saveError by remember { mutableStateOf<String?>(null) }
    var saveSuccess by remember { mutableStateOf<String?>(null) }
    var draftName by remember { mutableStateOf(event.name) }
    var draftLocation by remember { mutableStateOf(event.location) }
    var draftStartDate by remember { mutableStateOf(formatLocalDateInputFromIso(event.startDate)) }
    var draftStartTime by remember { mutableStateOf(timePickerDraftFromIso(event.startDate)) }
    var draftEndDate by remember { mutableStateOf(formatLocalDateInputFromIso(event.endDate)) }
    var draftEndTime by remember { mutableStateOf(timePickerDraftFromIso(event.endDate)) }
    var draftCapacity by remember { mutableStateOf(event.capacity) }
    var draftActive by remember { mutableStateOf(event.active) }
    var draftTicketTiers by remember { mutableStateOf(event.ticketTiers.map { it.toDraft() }) }
    var isSaving by remember { mutableStateOf(false) }

    var issueError by remember { mutableStateOf<String?>(null) }
    var issueSuccess by remember { mutableStateOf<TicketDto?>(null) }
    var issueHolderName by remember { mutableStateOf("") }
    var selectedIssueTierId by remember { mutableStateOf(currentEvent.ticketTiers.firstOrNull { it.active }?.id) }
    var isIssuing by remember { mutableStateOf(false) }

    fun syncDrafts(updated: EventDto) {
        currentEvent = updated
        draftName = updated.name
        draftLocation = updated.location
        draftStartDate = formatLocalDateInputFromIso(updated.startDate)
        draftStartTime = timePickerDraftFromIso(updated.startDate)
        draftEndDate = formatLocalDateInputFromIso(updated.endDate)
        draftEndTime = timePickerDraftFromIso(updated.endDate)
        draftCapacity = updated.capacity
        draftActive = updated.active
        draftTicketTiers = updated.ticketTiers.map { it.toDraft() }
        if (updated.ticketTiers.none { it.id == selectedIssueTierId && it.active }) {
            selectedIssueTierId = updated.ticketTiers.firstOrNull { it.active }?.id
        }
    }

    suspend fun loadStats() {
        isLoadingStats = true
        try {
            stats = apiClient.getEventStats(districtId, currentEvent.schoolId, currentEvent.id)
        } catch (_: Exception) {
            stats = null
        } finally {
            isLoadingStats = false
        }
    }

    LaunchedEffect(currentEvent.id) {
        loadStats()
    }

    fun submitSave() {
        val ticketTierRequests = draftTicketTiers.toUpdateRequests() ?: return
        val startTimeValue = draftStartTime.toLocalTimeValueOrNull()
        val endTimeValue = draftEndTime.toLocalTimeValueOrNull()
        val startDateIso = startTimeValue?.let { parseLocalDateAndTimeInputToIso(draftStartDate, it) }
        val endDateIso = endTimeValue?.let { parseLocalDateAndTimeInputToIso(draftEndDate, it) }
        if (
            draftName.isBlank() ||
            draftLocation.isBlank() ||
            draftStartDate.isBlank() ||
            !draftStartTime.isComplete() ||
            draftEndDate.isBlank() ||
            !draftEndTime.isComplete() ||
            startDateIso == null ||
            endDateIso == null ||
            isSaving
        ) return

        scope.launch {
            isSaving = true
            saveError = null
            saveSuccess = null
            try {
                val updated = apiClient.updateEvent(
                    eventId = currentEvent.id,
                    request = UpdateEventRequest(
                        districtId = districtId,
                        schoolId = currentEvent.schoolId,
                        name = draftName,
                        startDate = startDateIso,
                        endDate = endDateIso,
                        location = draftLocation,
                        capacity = draftCapacity,
                        replaceCapacity = true,
                        ticketTiers = ticketTierRequests,
                        active = draftActive,
                    ),
                )
                syncDrafts(updated)
                onUpdate(updated)
                saveSuccess = "Event details saved."
            } catch (exception: Exception) {
                saveError = exception.message ?: "Unable to save event."
            } finally {
                isSaving = false
            }
        }
    }

    fun submitArchiveToggle() {
        if (isSaving) return
        scope.launch {
            isSaving = true
            saveError = null
            saveSuccess = null
            try {
                val updated = apiClient.updateEvent(
                    eventId = currentEvent.id,
                    request = UpdateEventRequest(
                        districtId = districtId,
                        schoolId = currentEvent.schoolId,
                        name = null,
                        startDate = null,
                        endDate = null,
                        location = null,
                        capacity = null,
                        replaceCapacity = false,
                        ticketTiers = null,
                        active = !draftActive,
                    ),
                )
                syncDrafts(updated)
                onUpdate(updated)
                saveSuccess = if (updated.active) "Event restored." else "Event archived."
            } catch (exception: Exception) {
                saveError = exception.message ?: "Unable to update event state."
            } finally {
                isSaving = false
            }
        }
    }

    fun submitIssue() {
        val ticketTierId = selectedIssueTierId ?: return
        if (isIssuing) return
        scope.launch {
            isIssuing = true
            issueError = null
            issueSuccess = null
            try {
                val ticket = apiClient.issueTicket(
                    districtId = districtId,
                    schoolId = currentEvent.schoolId,
                    eventId = currentEvent.id,
                    request = IssueTicketRequest(
                        eventId = currentEvent.id,
                        districtId = districtId,
                        schoolId = currentEvent.schoolId,
                        ticketTierId = ticketTierId,
                        holderName = issueHolderName.ifBlank { null },
                    ),
                )
                issueSuccess = ticket
                loadStats()
            } catch (exception: Exception) {
                issueError = exception.message ?: "Unable to issue ticket."
            } finally {
                isIssuing = false
            }
        }
    }

    Div({
        style {
            property("position", "fixed")
            property("inset", "0")
            property("background-color", "rgba(0,0,0,0.58)")
            display(DisplayStyle.Flex)
            property("justify-content", "center")
            property("align-items", "center")
            property("z-index", "1000")
            padding(24.px)
        }
    }) {
        Div({
            style {
                property("background-color", theme.surface)
                borderRadius(32.px)
                padding(28.px)
                property("width", "min(980px, 100%)")
                property("max-height", "88vh")
                property("overflow-y", "auto")
                display(DisplayStyle.Flex)
                flexDirection(FlexDirection.Column)
                gap(20.px)
            }
        }) {
            H3({ style { margin(0.px); property("color", theme.onSurface) } }) {
                Text(currentEvent.name)
            }

            SectionCard(
                title = "Event Details",
                description = "Keep the event-level details stable while configuring the tiers operators will actually sell against.",
                theme = theme,
            ) {
                Div({
                    style {
                        display(DisplayStyle.Flex)
                        flexDirection(FlexDirection.Column)
                        gap(16.px)
                    }
                }) {
                    saveError?.let { StatusBanner(it, tone = BannerTone.Error, theme = theme) }
                    saveSuccess?.let { StatusBanner(it, tone = BannerTone.Success, theme = theme) }

                    FieldRow {
                        TextField(
                            theme = theme,
                            label = "Event Name",
                            value = draftName,
                            onValueChange = { draftName = it },
                        )
                        TextField(
                            theme = theme,
                            label = "Location",
                            value = draftLocation,
                            onValueChange = { draftLocation = it },
                        )
                    }
                    FieldRow {
                        LargePickerField(
                            theme = theme,
                            label = "Start Date",
                            value = draftStartDate,
                            onValueChange = { draftStartDate = it },
                            inputTypeOverride = "date",
                        )
                        AlarmTimePickerField(
                            theme = theme,
                            label = "Start Time",
                            value = draftStartTime,
                            onValueChange = { draftStartTime = it },
                        )
                    }
                    FieldRow {
                        LargePickerField(
                            theme = theme,
                            label = "End Date",
                            value = draftEndDate,
                            onValueChange = { draftEndDate = it },
                            inputTypeOverride = "date",
                        )
                        AlarmTimePickerField(
                            theme = theme,
                            label = "End Time",
                            value = draftEndTime,
                            onValueChange = { draftEndTime = it },
                        )
                    }
                    P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                        Text("Dates and times use your current local time zone: $localTimeZoneLabel. Tap the time field to open the picker wheel.")
                    }
                    CapacityField(
                        theme = theme,
                        label = "Event Capacity",
                        capacity = draftCapacity,
                        supportingText = "Use + / - for small changes. Tap the value to set an exact cap or explicitly switch back to Unlimited.",
                        dialogTitle = "Set Event Capacity",
                        dialogSubjectLabel = "event",
                        onCapacityChange = { draftCapacity = it },
                    )

                    Div({
                        style {
                            display(DisplayStyle.Flex)
                            gap(8.px)
                            property("flex-wrap", "wrap")
                        }
                    }) {
                        ChoiceChip(
                            label = if (draftActive) "Event Active" else "Event Archived",
                            isSelected = draftActive,
                            onClick = { draftActive = !draftActive },
                            theme = theme,
                        )
                    }

                    TicketTierEditor(
                        title = "Ticket Tiers",
                        drafts = draftTicketTiers,
                        statsByTierId = stats?.ticketTierStats?.associateBy { it.ticketTierId }.orEmpty(),
                        theme = theme,
                        onDraftsChange = { draftTicketTiers = it },
                    )

                    ActionButton(
                        label = if (isSaving) "Saving..." else "Save Event",
                        onClick = { submitSave() },
                        isDisabled = isSaving ||
                            draftName.isBlank() ||
                            draftLocation.isBlank() ||
                            draftStartDate.isBlank() ||
                            !draftStartTime.isComplete() ||
                            draftEndDate.isBlank() ||
                            !draftEndTime.isComplete() ||
                            draftStartTime.toLocalTimeValueOrNull()?.let { parseLocalDateAndTimeInputToIso(draftStartDate, it) } == null ||
                            draftEndTime.toLocalTimeValueOrNull()?.let { parseLocalDateAndTimeInputToIso(draftEndDate, it) } == null ||
                            !draftTicketTiers.canSubmit(),
                        theme = theme,
                    )
                }
            }

            SectionCard(
                title = "Ticket Overview",
                description = "Use this to sanity-check operator-facing inventory. Issuance is tier-specific now, and entry validation is moving toward dedicated gate tooling.",
                theme = theme,
            ) {
                Div({
                    style {
                        display(DisplayStyle.Flex)
                        flexDirection(FlexDirection.Column)
                        gap(16.px)
                    }
                }) {
                    val soldCount = stats?.soldCount ?: 0
                    val usedCount = stats?.usedCount ?: 0
                    val remainingCount = stats?.remainingCount
                    val eventSoldOut = stats?.capacity != null && remainingCount == 0
                    val selectedTierStats = stats?.ticketTierStats?.firstOrNull { it.ticketTierId == selectedIssueTierId }
                    val selectedTierSoldOut = selectedTierStats?.capacity != null && selectedTierStats.remainingCount == 0

                    P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                        Text("${formatLocalDateTimeDisplay(currentEvent.startDate)} · ${currentEvent.location} · ${formatStartingPrice(currentEvent)} · ${formatCapacitySummary(currentEvent.capacity)}")
                    }
                    if (isLoadingStats) {
                        P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                            Text("Loading event stats...")
                        }
                    } else {
                        Div({
                            style {
                                display(DisplayStyle.Flex)
                                gap(10.px)
                                property("flex-wrap", "wrap")
                            }
                        }) {
                            StatPill(label = "Tickets Sold", value = soldCount.toString(), theme = theme)
                            StatPill(label = "Checked In", value = usedCount.toString(), theme = theme)
                            StatPill(label = "Remaining", value = remainingCount?.toString() ?: "Unlimited", theme = theme)
                        }
                    }

                    if (eventSoldOut) {
                        StatusBanner(
                            message = "Event capacity has been reached.",
                            tone = BannerTone.Info,
                            theme = theme,
                        )
                    }

                    issueError?.let { StatusBanner(it, tone = BannerTone.Error, theme = theme) }
                    issueSuccess?.let { ticket ->
                        StatusBanner(
                            message = "Issued ${ticket.ticketTierName} ticket: ${ticket.ticketCode}",
                            tone = BannerTone.Success,
                            theme = theme,
                        )
                    }

                    if (currentEvent.ticketTiers.none { it.active }) {
                        StatusBanner(
                            message = "Activate at least one tier before issuing tickets.",
                            tone = BannerTone.Info,
                            theme = theme,
                        )
                    } else {
                        Div({
                            style {
                                display(DisplayStyle.Flex)
                                flexDirection(FlexDirection.Column)
                                gap(12.px)
                            }
                        }) {
                            P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                                Text("Issue against ticket tier")
                            }
                            Div({
                                style {
                                    display(DisplayStyle.Flex)
                                    gap(8.px)
                                    property("flex-wrap", "wrap")
                                }
                            }) {
                                currentEvent.ticketTiers.filter { it.active }.forEach { ticketTier ->
                                    val ticketTierStats = stats?.ticketTierStats?.firstOrNull { it.ticketTierId == ticketTier.id }
                                    ChoiceChip(
                                        label = tierSummary(ticketTier, ticketTierStats),
                                        isSelected = selectedIssueTierId == ticketTier.id,
                                        onClick = { selectedIssueTierId = ticketTier.id },
                                        theme = theme,
                                    )
                                }
                            }
                            FieldRow {
                                TextField(
                                    theme = theme,
                                    label = "Holder Name (optional)",
                                    value = issueHolderName,
                                    onValueChange = { issueHolderName = it },
                                    placeholder = "Walk-up guest",
                                )
                            }
                            if (selectedTierSoldOut) {
                                StatusBanner(
                                    message = "${selectedTierStats.ticketTierName} tier is sold out.",
                                    tone = BannerTone.Info,
                                    theme = theme,
                                )
                            }
                            ActionButton(
                                label = if (isIssuing) "Issuing..." else "Issue Ticket",
                                onClick = { submitIssue() },
                                isDisabled = isIssuing || selectedIssueTierId == null || eventSoldOut || selectedTierSoldOut,
                                theme = theme,
                            )
                        }
                    }
                }
            }

            Div({
                style {
                    display(DisplayStyle.Flex)
                    gap(8.px)
                    property("justify-content", "flex-end")
                    property("flex-wrap", "wrap")
                }
            }) {
                ActionButton(
                    label = if (draftActive) "Archive Event" else "Restore Event",
                    onClick = { submitArchiveToggle() },
                    isPrimary = false,
                    isDisabled = isSaving,
                    theme = theme,
                )
                ActionButton(
                    label = "Close",
                    onClick = onClose,
                    isPrimary = false,
                    theme = theme,
                )
            }
        }
    }
}

