@Composable
private fun <T> WheelPickerColumn(
    id: String,
    theme: MaterialThemePalette,
    label: String,
    options: List<WheelOption<T>>,
    selectedValue: T,
    onValueChange: (T) -> Unit,
) {
    val selectedIndex = options.indexOfFirst { it.value == selectedValue }.coerceAtLeast(0)
    var snapTimeoutId by remember(id) { mutableStateOf<Int?>(null) }

    fun alignWheelTo(index: Int) {
        window.setTimeout({
            val element = document.getElementById(id) as? HTMLElement ?: return@setTimeout
            element.scrollTop = index.coerceIn(0, options.lastIndex) * TimeWheelRowHeightPx.toDouble()
        }, 0)
    }

    LaunchedEffect(id, selectedIndex) {
        val element = document.getElementById(id) as? HTMLElement
        val targetTop = selectedIndex * TimeWheelRowHeightPx.toDouble()
        if (element == null || abs(element.scrollTop - targetTop) > 1.0) {
            alignWheelTo(selectedIndex)
        }
    }

    Div({
        style {
            display(DisplayStyle.Flex)
            flexDirection(FlexDirection.Column)
            gap(10.px)
            property("min-width", "96px")
            property("flex", "1 1 96px")
            property("max-width", "132px")
        }
    }) {
        P({
            style {
                margin(0.px)
                property("color", theme.onSurfaceVariant)
                property("font-size", "0.75rem")
                property("font-weight", "700")
                property("letter-spacing", "0.08em")
                property("text-transform", "uppercase")
                property("text-align", "center")
            }
        }) {
            Text(label)
        }

        Div({
            style {
                property("position", "relative")
                property("height", "${TimeWheelRowHeightPx * TimeWheelVisibleRows}px")
                borderRadius(22.px)
                property("border", "1px solid ${theme.outlineVariant}")
                property(
                    "background",
                    "linear-gradient(180deg, ${theme.surfaceContainerHighest} 0%, ${theme.surface} 100%)"
                )
                property("box-shadow", "0 18px 34px ${theme.shadow}, inset 0 1px 0 ${theme.scrim}")
                property("overflow", "hidden")
            }
        }) {
            Div({
                style {
                    property("position", "absolute")
                    property("left", "10px")
                    property("right", "10px")
                    property("top", "calc(50% - ${TimeWheelRowHeightPx / 2}px)")
                    property("height", "${TimeWheelRowHeightPx}px")
                    property("border-radius", "18px")
                    property("border", "1px solid ${theme.primary}")
                    property("background", theme.secondaryContainer)
                    property("opacity", "0.82")
                    property("pointer-events", "none")
                    property("z-index", "1")
                }
            })

            Div({
                style {
                    property("position", "absolute")
                    property("left", "0")
                    property("right", "0")
                    property("top", "0")
                    property("height", "${TimeWheelRowHeightPx * TimeWheelSidePaddingRows}px")
                    property(
                        "background",
                        "linear-gradient(180deg, ${theme.surface} 0%, rgba(255,255,255,0) 100%)"
                    )
                    property("pointer-events", "none")
                    property("z-index", "2")
                }
            })

            Div({
                style {
                    property("position", "absolute")
                    property("left", "0")
                    property("right", "0")
                    property("bottom", "0")
                    property("height", "${TimeWheelRowHeightPx * TimeWheelSidePaddingRows}px")
                    property(
                        "background",
                        "linear-gradient(0deg, ${theme.surface} 0%, rgba(255,255,255,0) 100%)"
                    )
                    property("pointer-events", "none")
                    property("z-index", "2")
                }
            })

            Div(attrs = {
                id(id)
                onScroll {
                    val element = document.getElementById(id) as? HTMLElement ?: return@onScroll
                    val nearestIndex = (element.scrollTop / TimeWheelRowHeightPx).roundToInt().coerceIn(0, options.lastIndex)
                    val nearestValue = options[nearestIndex].value
                    if (nearestValue != selectedValue) {
                        onValueChange(nearestValue)
                    }
                    snapTimeoutId?.let { timeoutId -> window.clearTimeout(timeoutId) }
                    snapTimeoutId = window.setTimeout({
                        val currentElement = document.getElementById(id) as? HTMLElement ?: return@setTimeout
                        currentElement.scrollTop = nearestIndex * TimeWheelRowHeightPx.toDouble()
                    }, 90)
                }
                style {
                    property("height", "100%")
                    property("overflow-y", "auto")
                    property("scroll-snap-type", "y mandatory")
                    property("scrollbar-width", "none")
                    property("-ms-overflow-style", "none")
                    property("position", "relative")
                    property("z-index", "0")
                }
            }) {
                repeat(TimeWheelSidePaddingRows) {
                    Div({
                        style {
                            property("height", "${TimeWheelRowHeightPx}px")
                            property("scroll-snap-align", "center")
                        }
                    })
                }

                options.forEachIndexed { index, option ->
                    val isSelected = option.value == selectedValue
                    Div(attrs = {
                        onClick {
                            onValueChange(option.value)
                            alignWheelTo(index)
                        }
                        style {
                            property("height", "${TimeWheelRowHeightPx}px")
                            display(DisplayStyle.Flex)
                            property("align-items", "center")
                            property("justify-content", "center")
                            property("scroll-snap-align", "center")
                            property("cursor", "pointer")
                            property("color", if (isSelected) theme.onSecondaryContainer else theme.onSurfaceVariant)
                            property("font-size", if (isSelected) "1.08rem" else "0.98rem")
                            property("font-weight", if (isSelected) "700" else "500")
                            property("opacity", if (isSelected) "1" else "0.72")
                            property("transition", "color 120ms ease, opacity 120ms ease, font-size 120ms ease")
                            property("user-select", "none")
                        }
                    }) {
                        Text(option.label)
                    }
                }

                repeat(TimeWheelSidePaddingRows) {
                    Div({
                        style {
                            property("height", "${TimeWheelRowHeightPx}px")
                            property("scroll-snap-align", "center")
                        }
                    })
                }
            }
        }
    }
}

