                    TextField(
                        theme = theme,
                        label = "Tier Name",
                        value = draft.name,
                        onValueChange = { value ->
                            onDraftsChange(drafts.updateAt(index) { existing -> existing.copy(name = value) })
                        },
                        placeholder = "General Admission",
