                        },
                        placeholder = "5.00",
                    )
                    CapacityField(
                        theme = theme,
                        label = "Tier Capacity",
                        capacity = parseCapacityInput(draft.capacityInput),
                        dialogTitle = "Set Tier Capacity",
                        dialogSubjectLabel = "tier",
                        onCapacityChange = { updatedCapacity ->
                            onDraftsChange(
                                drafts.updateAt(index) { existing ->
                                    existing.copy(capacityInput = formatCapacityInput(updatedCapacity))
                                }
                            )
                        },
                    )
                }

                ticketTierStats?.let { tierStats ->
                    Div({
                        style {
                            display(DisplayStyle.Flex)
                            gap(10.px)
                            property("flex-wrap", "wrap")
                        }
                    }) {
                        StatPill(label = "Sold", value = tierStats.soldCount.toString(), theme = theme)
                        StatPill(label = "Remaining", value = tierStats.remainingCount?.toString() ?: "Unlimited", theme = theme)
                    }
                    if (tierStats.capacity != null && tierStats.remainingCount == 0) {
                        StatusBanner(
                            message = "${tierStats.ticketTierName} tier is sold out.",
                            tone = BannerTone.Info,
                            theme = theme,
                        )
                    }
                }

                Div({
                    style {
                        display(DisplayStyle.Flex)
                        flexDirection(FlexDirection.Column)
                        gap(10.px)
                    }
                }) {
                    P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                        Text("Entitlements")
                    }
