                        P({ style { margin(0.px); property("color", theme.onSurfaceVariant) } }) {
                            Text("No entitlements on this tier yet.")
                        }
                    } else {
                        draft.entitlements.forEachIndexed { entitlementIndex, entitlementDraft ->
                            EntitlementEditor(
                                draft = entitlementDraft,
                                theme = theme,
                                onChange = { updatedEntitlement ->
                                    onDraftsChange(
                                        drafts.updateAt(index) { currentTier ->
                                            currentTier.copy(
                                                entitlements = currentTier.entitlements.updateAt(entitlementIndex) { updatedEntitlement }
                                            )
                                        }
                                    )
                                },
                                onRemove = {
                                    onDraftsChange(
                                        drafts.updateAt(index) { currentTier ->
                                            currentTier.copy(
                                                entitlements = currentTier.entitlements.filterIndexed { currentEntitlementIndex, _ ->
                                                    currentEntitlementIndex != entitlementIndex
                                                }
                                            )
                                        }
                                    )
                                },
                            )
                        }
                    }
                    ActionButton(
                        label = "Add Entitlement",
                        onClick = {
                            onDraftsChange(
                                drafts.updateAt(index) { currentTier ->
                                    currentTier.copy(entitlements = currentTier.entitlements + TicketEntitlementDraft())
                                }
                            )
                        },
                        isPrimary = false,
                        theme = theme,
                    )
                }
            }
        }

        ActionButton(
            label = "Add Ticket Tier",
            onClick = { onDraftsChange(drafts + defaultTicketTierDraft()) },
            isPrimary = false,
            theme = theme,
        )
    }
}

