private fun defaultTicketTierDraft() = TicketTierDraft(
    name = "General Admission",
    priceInput = "",
    capacityInput = "",
    active = true,
)

private fun TicketTierDto.toDraft() = TicketTierDraft(
    id = id,
    name = name,
    priceInput = formatMoney(priceAmount.toLong()),
    capacityInput = formatCapacityInput(capacity),
    active = active,
    entitlements = entitlements.map { it.toDraft() },
)

private fun TicketEntitlementDto.toDraft() = TicketEntitlementDraft(
    type = type,
    label = label,
    amountInput = amount?.toString().orEmpty(),
    quantityInput = quantity?.toString().orEmpty(),
)

private fun List<TicketTierDraft>.canSubmit(): Boolean =
    isNotEmpty() && all { it.canSubmit() }

private fun TicketTierDraft.canSubmit(): Boolean =
    name.isNotBlank() &&
        parseMoneyInput(priceInput) != null &&
        isCapacityInputValid(capacityInput) &&
        entitlements.all { it.isValid() }

private fun TicketEntitlementDraft.isValid(): Boolean {
    if (label.isBlank() && amountInput.isBlank() && quantityInput.isBlank()) {
        return true
    }
    val amountIsValid = amountInput.isBlank() || amountInput.trim().toIntOrNull()?.let { it > 0 } == true
    val quantityIsValid = quantityInput.isBlank() || quantityInput.trim().toIntOrNull()?.let { it > 0 } == true
    return label.isNotBlank() && amountIsValid && quantityIsValid
}

private fun List<TicketTierDraft>.toCreateRequests(): List<CreateTicketTierRequest>? =
    if (!canSubmit()) {
        null
    } else {
        map { draft ->
            CreateTicketTierRequest(
                name = draft.name.trim(),
                priceAmount = parseMoneyInput(draft.priceInput)?.toInt() ?: return null,
                capacity = parseCapacityInput(draft.capacityInput),
                active = draft.active,
                entitlements = draft.entitlements.mapNotNull { it.toDtoOrNull() },
            )
        }
    }

private fun List<TicketTierDraft>.toUpdateRequests(): List<UpdateTicketTierRequest>? =
    if (!canSubmit()) {
        null
    } else {
        map { draft ->
            UpdateTicketTierRequest(
                id = draft.id,
                name = draft.name.trim(),
                priceAmount = parseMoneyInput(draft.priceInput)?.toInt() ?: return null,
                capacity = parseCapacityInput(draft.capacityInput),
                replaceCapacity = true,
                active = draft.active,
                entitlements = draft.entitlements.mapNotNull { it.toDtoOrNull() },
            )
        }
    }

private fun TicketEntitlementDraft.toDtoOrNull(): TicketEntitlementDto? {
    if (label.isBlank() && amountInput.isBlank() && quantityInput.isBlank()) {
        return null
    }
    return TicketEntitlementDto(
        type = type,
        label = label.trim(),
        amount = amountInput.trim().takeIf(String::isNotBlank)?.toIntOrNull(),
        quantity = quantityInput.trim().takeIf(String::isNotBlank)?.toIntOrNull(),
    )
}

private fun <T> List<T>.updateAt(index: Int, update: (T) -> T): List<T> =
    mapIndexed { currentIndex, value -> if (currentIndex == index) update(value) else value }

private fun buildCreateEventMissingRequirements(
    eventName: String,
    location: String,
    startDate: String,
    startTime: TimePickerDraft,
    endDate: String,
    endTime: TimePickerDraft,
    ticketTiers: List<TicketTierDraft>,
): List<String> {
    val missing = mutableListOf<String>()
    val startTimeValue = startTime.toLocalTimeValueOrNull()
    val endTimeValue = endTime.toLocalTimeValueOrNull()

    if (eventName.isBlank()) missing += "Enter an event name."
    if (location.isBlank()) missing += "Enter a location."
    if (startDate.isBlank()) missing += "Choose a start date."
    if (!startTime.isComplete()) missing += "Choose a start time."
    if (endDate.isBlank()) missing += "Choose an end date."
    if (!endTime.isComplete()) missing += "Choose an end time."

    if (
        startDate.isNotBlank() &&
        startTimeValue != null &&
        parseLocalDateAndTimeInputToIso(startDate, startTimeValue) == null
    ) {
        missing += "Start date and time must be valid."
    }

    if (
        endDate.isNotBlank() &&
        endTimeValue != null &&
        parseLocalDateAndTimeInputToIso(endDate, endTimeValue) == null
    ) {
        missing += "End date and time must be valid."
    }

    if (ticketTiers.isEmpty()) {
        missing += "Add at least one ticket tier."
    } else {
        ticketTiers.forEachIndexed { index, tier ->
            val tierNumber = index + 1
            if (tier.name.isBlank()) {
                missing += "Tier $tierNumber needs a name."
            }
            if (parseMoneyInput(tier.priceInput) == null) {
                missing += "Tier $tierNumber needs a valid price."
            }
            if (!isCapacityInputValid(tier.capacityInput)) {
                missing += "Tier $tierNumber capacity must be a whole number or Unlimited."
            }
            if (tier.entitlements.any { !it.isValid() }) {
                missing += "Tier $tierNumber has an incomplete entitlement."
            }
        }
    }

    return missing
}

private fun TimePickerDraft.isComplete(): Boolean =
    hour != null && minute != null

private fun TimePickerDraft.withCurrentTimeDefaults(): TimePickerDraft {
    val fallback = browserCurrentTimeDraft()
    return TimePickerDraft(
        hour = hour ?: fallback.hour,
        minute = minute ?: fallback.minute,
        meridiem = if (hour == null && minute == null) fallback.meridiem else meridiem,
    )
}

private fun TimePickerDraft.toLocalTimeValueOrNull(): String? {
    val selectedHour = hour ?: return null
    val selectedMinute = minute ?: return null
    val hour24 = when (meridiem) {
        TimeMeridiem.AM -> if (selectedHour == 12) 0 else selectedHour
        TimeMeridiem.PM -> if (selectedHour == 12) 12 else selectedHour + 12
    }
    return "${hour24.toString().padStart(2, '0')}:${selectedMinute.toString().padStart(2, '0')}"
}

private fun timePickerDraftFromIso(value: String): TimePickerDraft =
    timePickerDraftFromLocalTime(formatLocalTimeInputFromIso(value))

private fun timePickerDraftFromLocalTime(value: String): TimePickerDraft {
    val normalized = value.trim()
    if (normalized.isEmpty()) return TimePickerDraft()

    val hour24 = normalized.substringBefore(':').toIntOrNull() ?: return TimePickerDraft()
    val minute = normalized.substringAfter(':').toIntOrNull() ?: return TimePickerDraft()
    if (hour24 !in 0..23 || minute !in 0..59) return TimePickerDraft()

    val meridiem = if (hour24 >= 12) TimeMeridiem.PM else TimeMeridiem.AM
    val hour12 = when (val normalizedHour = hour24 % 12) {
        0 -> 12
        else -> normalizedHour
    }

    return TimePickerDraft(
        hour = hour12,
        minute = minute,
        meridiem = meridiem,
    )
}

private fun browserCurrentTimeDraft(): TimePickerDraft {
    val now = Date()
    val hour24 = now.getHours()
    val minute = now.getMinutes()
    val meridiem = if (hour24 >= 12) TimeMeridiem.PM else TimeMeridiem.AM
    val hour12 = when (val normalizedHour = hour24 % 12) {
        0 -> 12
        else -> normalizedHour
    }
    return TimePickerDraft(
        hour = hour12,
        minute = minute,
        meridiem = meridiem,
    )
}

private fun parseCapacityInput(value: String): Int? =
    value.trim().takeIf(String::isNotEmpty)?.toIntOrNull()

private fun isCapacityInputValid(value: String): Boolean =
    value.isBlank() || value.trim().toIntOrNull()?.let { it >= 0 } == true

private fun formatCapacityInput(capacity: Int?): String = capacity?.toString().orEmpty()

private fun formatStartingPrice(event: EventDto): String =
    event.startingPriceAmount?.let { "From ${formatMoney(it.toLong())}" } ?: "No active ticket tiers"

private fun formatCapacitySummary(capacity: Int?): String =
    capacity?.let { "Cap $it" } ?: "Unlimited"

private fun tierSummary(
    ticketTier: TicketTierDto,
    ticketTierStats: EventTicketTierStatsDto? = null,
): String =
    buildString {
        append(ticketTier.name)
        append(" · ")
        append(formatMoney(ticketTier.priceAmount.toLong()))
        append(" · ")
        append(formatCapacitySummary(ticketTier.capacity))
        ticketTierStats?.let {
            append(" · ")
            append(
                if (it.capacity != null && it.remainingCount == 0) {
                    "sold out"
                } else {
                    "${it.soldCount} sold"
                }
            )
        }
        if (!ticketTier.active) {
            append(" · inactive")
        }
    }
