    private fun url(path: String): String = "$normalizedBaseUrl$path"

    private suspend inline fun <reified T> request(
        includeAuth: Boolean = true,
        crossinline block: suspend () -> HttpResponse,
    ): T {
        val response = block()
        if (!response.status.isSuccess()) {
            val details = response.bodyAsText()
            throw AdminApiException(
                formatErrorMessage(response = response, details = details),
                response.status.value,
            )
        }
        return response.body()
    }

    private fun HttpRequestBuilder.applyAdminAuth() {
        accessToken?.takeIf(String::isNotBlank)?.let { token ->
            header(HttpHeaders.Authorization, "Bearer $token")
        }
    }

    private fun formatErrorMessage(response: HttpResponse, details: String): String {
        val trimmed = details.trim()
        if (trimmed.isBlank()) {
            if (response.status.value == 401) {
                return "Your admin session is not available. Sign in again."
            }
            if (response.status.value == 403) {
                return "You do not have access to that district or admin action."
            }
            return "Request failed with HTTP ${response.status.value}"
        }

        if (trimmed.startsWith("{")) {
            runCatching {
                val jsonObject = Json.parseToJsonElement(trimmed).jsonObject
                jsonObject["error"]?.jsonPrimitive?.contentOrNull
                    ?: jsonObject["message"]?.jsonPrimitive?.contentOrNull
            }.getOrNull()?.takeIf(String::isNotBlank)?.let { return it }
        }

        if (trimmed.contains("Cannot ") && trimmed.contains("/api/")) {
            return "Local dev routing is out of date. Restart ./gradlew jsBrowserDevelopmentRun and refresh the browser."
        }

        if (trimmed.contains("<html", ignoreCase = true)) {
            val routeMessage = Regex(
                pattern = "(?is)<pre>(.*?)</pre>",
            ).find(trimmed)?.groups?.get(1)?.value?.trim()

            return routeMessage ?: "Request failed with HTTP ${response.status.value}"
        }

        return trimmed
    }

    private companion object {
        fun buildHttpClient(): HttpClient = HttpClient {
            expectSuccess = false
            install(ContentNegotiation) {
                json(
                    Json {
                        ignoreUnknownKeys = true
                        explicitNulls = false
                    }
                )
            }
        }
    }
}

class AdminApiException(
    message: String,
    val statusCode: Int? = null,
) : Exception(message)
